      IF (NINT(T3) .NE. 0) THEN
         T6 = 0
      ELSE
         T6 = 1
      ENDIF

! 1120:[inv] Interpolated Logic Inverter 
      IF (NINT(T1) .NE. 0) THEN
         T4 = 0
      ELSE
         T4 = 1
      ENDIF

! 1130:[div] Divider 
!
      IF (ABS(INV_Vbase) .LT. 1.0E-10) THEN
         IF (INV_Vbase .LT. 0.0)  THEN
            Idc = -1.0E10 * RT_57
         ELSE
            Idc =  1.0E10 * RT_57
         ENDIF
      ELSE
         Idc = RT_57 / INV_Vbase
      ENDIF
!

! 1140:[div] Divider 
!
      IF (ABS(RT_11) .LT. 1.0E-10) THEN
         IF (RT_11 .LT. 0.0)  THEN
            fpu = -1.0E10 * PLL_f
         ELSE
            fpu =  1.0E10 * PLL_f
         ENDIF
      ELSE
         fpu = PLL_f / RT_11
      ENDIF
!

! 1150:[mult] Multiplier 
      Cconv_G = RT_43 * Cgain

! 1160:[realpole] Real Pole 
!  Real_Pole
      Vq = REALPOLE(0,1,0,1.0,0.02,RT_31,0.0,-10.0,10.0)

! 1170:[div] Divider 
!
      IF (ABS(INV_Vbase_LNpk) .LT. 1.0E-10) THEN
         IF (INV_Vbase_LNpk .LT. 0.0)  THEN
            RT_29 = -1.0E10 * RT_30
         ELSE
            RT_29 =  1.0E10 * RT_30
         ENDIF
      ELSE
         RT_29 = RT_30 / INV_Vbase_LNpk
      ENDIF
!

! 1180:[realpole] Real Pole 
!  Real_Pole
      Vd = REALPOLE(0,1,0,1.0,0.02,RT_29,0.0,-10.0,10.0)

! 1190:[mult] Multiplier 
      Lconv_G = RT_39 * Lgain

! 1200:[pgb] Output Channel 'Ref_a'

      PGB(IPGB+7) = Ref_a

! 1210:[pgb] Output Channel 'Iaa'

      PGB(IPGB+8) = Iaa

! 1220:[realpole] Real Pole 
!  Real_Pole
      Iq = REALPOLE(0,1,0,1.0,0.02,RT_26,0.0,-10.0,10.0)

! 1230:[div] Divider 
!
      IF (ABS(Vdc_Base) .LT. 1.0E-10) THEN
         IF (Vdc_Base .LT. 0.0)  THEN
            Idc_base = -1.0E10 * Sbase
         ELSE
            Idc_base =  1.0E10 * Sbase
         ENDIF
      ELSE
         Idc_base = Sbase / Vdc_Base
      ENDIF
!

! 1240:[div] Divider 
!
      IF (ABS(INV_Ibase_pk) .LT. 1.0E-10) THEN
         IF (INV_Ibase_pk .LT. 0.0)  THEN
            RT_25 = -1.0E10 * RT_22
         ELSE
            RT_25 =  1.0E10 * RT_22
         ENDIF
      ELSE
         RT_25 = RT_22 / INV_Ibase_pk
      ENDIF
!

! 1250:[realpole] Real Pole 
!  Real_Pole
      Id = REALPOLE(0,1,0,1.0,0.02,RT_25,0.0,-10.0,10.0)

! 1260:[pgb] Output Channel 'Vq'

      PGB(IPGB+9) = Vq

! 1270:[pgb] Output Channel 'Vd'

      PGB(IPGB+10) = Vd

! 1280:[pgb] Output Channel 'IQord'

      PGB(IPGB+11) = IQord

! 1290:[pgb] Output Channel 'IPord'

      PGB(IPGB+12) = IPord

! 1300:[pgb] Output Channel 'Iq'

      PGB(IPGB+13) = Iq

! 1310:[varrlc] Variable R, L or C  
      CALL E_VARRLC1_EXE(2 ,SS(1) ,  (IBRCH(1)+27), 0, Cconv_G, 0.0)

! 1320:[varrlc] Variable R, L or C  
      CALL E_VARRLC1_EXE(2 ,SS(1) ,  (IBRCH(1)+26), 0, Cconv_G, 0.0)

! 1330:[varrlc] Variable R, L or C  
      CALL E_VARRLC1_EXE(2 ,SS(1) ,  (IBRCH(1)+25), 0, Cconv_G, 0.0)

! 1340:[pgb] Output Channel 'Id'

      PGB(IPGB+14) = Id

! 1360:[pgb] Output Channel 'Theta_P'

      PGB(IPGB+15) = Theta_P

! 1370:[peswitch] Power electronic switch 
! Power Electronic Switch Model: IGBT
      CALL COMPONENT_ID(ICALL_NO,739518771)
      CALL PESWITCH1_EXE(SS(1), (IBRCH(1)+46), T2, 0.0)

! 1380:[varrlc] Variable R, L or C  
      CALL E_VARRLC1_EXE(1 ,SS(1) ,  (IBRCH(1)+7), 0, Lconv_G, 0.0)
      CALL E_VARRLC1_EXE(1 ,SS(1) ,  (IBRCH(1)+8), 0, Lconv_G, 0.0)
      CALL E_VARRLC1_EXE(1 ,SS(1) ,  (IBRCH(1)+9), 0, Lconv_G, 0.0)

! 1390:[peswitch] Power electronic switch 
! Power Electronic Switch Model: IGBT
      CALL COMPONENT_ID(ICALL_NO,1925183631)
      CALL PESWITCH1_EXE(SS(1), (IBRCH(1)+44), T6, 0.0)

! 1400:[pgb] Output Channel 'PLL_f'

      PGB(IPGB+16) = RT_27

! 1410:[peswitch] Power electronic switch 
! Power Electronic Switch Model: IGBT
      CALL COMPONENT_ID(ICALL_NO,96539355)
      CALL PESWITCH1_EXE(SS(1), (IBRCH(1)+42), T4, 0.0)

! 1450:[peswitch] Power electronic switch 
! Power Electronic Switch Model: IGBT
      CALL COMPONENT_ID(ICALL_NO,479509263)
