      CALL COMPONENT_ID(ICALL_NO,310352140)
      CALL PESWITCH1_EXE(SS(1), (IBRCH(1)+34), 1, 0.0)

! 1:[peswitch] Power electronic switch 
! Power Electronic Switch Model: Diode
      CALL COMPONENT_ID(ICALL_NO,1430221811)
      CALL PESWITCH1_EXE(SS(1), (IBRCH(1)+36), 1, 0.0)

!---------------------------------------
! Feedbacks and transfers to storage
!---------------------------------------

      STOF(ISTOF + 16) = RT_1
      STOF(ISTOF + 17) = RT_2
