      STOF(ISTOF + 39) = DB
      STOI(ISTOI + 1) = DBLK
      STOI(ISTOI + 2) = RST
      STOF(ISTOF + 40) = RT_12
      STOF(ISTOF + 41) = RT_13
      STOF(ISTOF + 42) = RT_14
      STOF(ISTOF + 43) = RT_15
      STOF(ISTOF + 44) = RT_16
      STOF(ISTOF + 45) = RT_17
      STOF(ISTOF + 46) = Start
      STOF(ISTOF + 47) = RT_18
