      SUBROUTINE IBR_AVM_2_1_1Out()

!---------------------------------------
! Standard includes
!---------------------------------------

      INCLUDE 'nd.h'
      INCLUDE 'emtconst.h'
      INCLUDE 'emtstor.h'
      INCLUDE 's0.h'
      INCLUDE 's1.h'
      INCLUDE 's2.h'
      INCLUDE 's4.h'
      INCLUDE 'branches.h'
      INCLUDE 'pscadv3.h'
      INCLUDE 'fnames.h'
      INCLUDE 'radiolinks.h'
      INCLUDE 'matlab.h'
      INCLUDE 'rtconfig.h'

!---------------------------------------
! Function/Subroutine Declarations
!---------------------------------------

      REAL    EMTDC_VVDC    ! 
      REAL    P3PH3         ! 
!     SUBR    DGTL_RMS3     ! '3 Phase Digital RMS Meter'
      REAL    Q3PH3         ! 
      REAL    REALPOLE      ! Real Pole
!     SUBR    REEC_A_1_2_1_1Out  ! 
!     SUBR    REGC_A_1_2_1_1Out  ! 
      REAL    VBRANCH       ! Voltage across the branch

!---------------------------------------
! Variable Declarations
!---------------------------------------


! Electrical Node Indices
      INTEGER  NT_1(3), NT_2(3), NT_5(3), NT_6(3)
      INTEGER  NT_8

! Control Signals
      REAL     RT_5, RT_6, RT_8, RT_10, RT_11
      REAL     RT_18, Q, RT_21, Ia, Ib, Ic, Vrms
      REAL     RT_34, RT_35, RT_36, RT_37, RT_38
      REAL     RT_41, RT_44, RT_45, RT_46, Ve
      REAL     RT_48, RT_49, RT_50, RT_51, Pe, P
      REAL     Pfilter, Qfilter, Idc_out, RT_52
      REAL     Edc, RT_54, RT_56, RT_58, Q0
      REAL     Iibr(3), Vibr(3), Vc, Vb, Va

! Internal Variables
      INTEGER  IVD1_1
      REAL     RVD1_1

! Indexing variables
      INTEGER ICALL_NO                            ! Module call num
      INTEGER ISTOL, ISTOI, ISTOF, ISTOC, IT_0    ! Storage Indices
      INTEGER IPGB                                ! Control/Monitoring
      INTEGER ISUBS, SS(1), IBRCH(1), INODE       ! SS/Node/Branch/Xfmr


!---------------------------------------
! Local Indices
!---------------------------------------

! Dsdyn <-> Dsout transfer index storage

      NTXFR = NTXFR + 1

      ISTOL = TXFR(NTXFR,1)
      ISTOI = TXFR(NTXFR,2)
      ISTOF = TXFR(NTXFR,3)
      ISTOC = TXFR(NTXFR,4)

! Increment and assign runtime configuration call indices

      ICALL_NO  = NCALL_NO
      NCALL_NO  = NCALL_NO + 1

! Increment global storage indices

      IPGB      = NPGB
      NPGB      = NPGB + 21
      NCX       = NCX + 0
      INODE     = NNODE + 2
      NNODE     = NNODE + 32
      NCSCS     = NCSCS + 0
      NCSCR     = NCSCR + 0

! Initialize Subsystem Mapping

      ISUBS = NSUBS + 0
      NSUBS = NSUBS + 1

      DO IT_0 = 1,1
         SS(IT_0) = SUBS(ISUBS + IT_0)
      END DO

! Initialize Branch Mapping.

      IBRCH(1)     = NBRCH(SS(1))
      NBRCH(SS(1)) = NBRCH(SS(1)) + 48
!---------------------------------------
! Transfers from storage arrays
!---------------------------------------

      RT_5     = STOF(ISTOF + 30)
      RT_6     = STOF(ISTOF + 32)
      RT_8     = STOF(ISTOF + 34)
      RT_10    = STOF(ISTOF + 36)
      RT_11    = STOF(ISTOF + 38)
      RT_18    = STOF(ISTOF + 47)
      Q        = STOF(ISTOF + 50)
      RT_21    = STOF(ISTOF + 53)
      Ia       = STOF(ISTOF + 54)
      Ib       = STOF(ISTOF + 55)
      Ic       = STOF(ISTOF + 56)
      Vrms     = STOF(ISTOF + 74)
      RT_34    = STOF(ISTOF + 79)
      RT_35    = STOF(ISTOF + 80)
      RT_36    = STOF(ISTOF + 81)
      RT_37    = STOF(ISTOF + 94)
      RT_38    = STOF(ISTOF + 95)
      RT_41    = STOF(ISTOF + 98)
      RT_44    = STOF(ISTOF + 103)
      RT_45    = STOF(ISTOF + 105)
      RT_46    = STOF(ISTOF + 106)
      Ve       = STOF(ISTOF + 108)
      RT_48    = STOF(ISTOF + 111)
      RT_49    = STOF(ISTOF + 112)
      RT_50    = STOF(ISTOF + 114)
      RT_51    = STOF(ISTOF + 115)
      Pe       = STOF(ISTOF + 116)
      P        = STOF(ISTOF + 117)
      Pfilter  = STOF(ISTOF + 118)
      Qfilter  = STOF(ISTOF + 119)
      Idc_out  = STOF(ISTOF + 120)
      RT_52    = STOF(ISTOF + 122)
      Edc      = STOF(ISTOF + 123)
      RT_54    = STOF(ISTOF + 125)
      RT_56    = STOF(ISTOF + 128)
      RT_58    = STOF(ISTOF + 130)
      Q0       = STOF(ISTOF + 134)
      Vc       = STOF(ISTOF + 146)
      Vb       = STOF(ISTOF + 147)
      Va       = STOF(ISTOF + 148)

! Array (1:3) quantities...
      DO IT_0 = 1,3
         Iibr(IT_0) = STOF(ISTOF + 139 + IT_0)
         Vibr(IT_0) = STOF(ISTOF + 142 + IT_0)
      END DO


!---------------------------------------
! Electrical Node Lookup
!---------------------------------------

      NT_8  = NODE(INODE + 23)

! Array (1:3) quantities...
      DO IT_0 = 1,3
         NT_1(IT_0) = NODE(INODE + 3 + IT_0)
         NT_2(IT_0) = NODE(INODE + 6 + IT_0)
         NT_5(IT_0) = NODE(INODE + 15 + IT_0)
         NT_6(IT_0) = NODE(INODE + 18 + IT_0)
      END DO

!---------------------------------------
! Configuration of Models
!---------------------------------------

      IF ( TIMEZERO ) THEN
         FILENAME = 'IBR_AVM_2_1_1.dta'
         CALL EMTDC_OPENFILE
         SECTION = 'DATADSO:'
         CALL EMTDC_GOTOSECTION
      ENDIF
!---------------------------------------
! Generated code from module definition
!---------------------------------------


! 40:[voltmetergnd] Voltmeter (Line - Ground) 'Edc'
      Edc = EMTDC_VVDC(SS(1), NT_8, 0)

! 50:[ammeter] Current Meter 'Idc_out'
      Idc_out = ( CBR((IBRCH(1)+16), SS(1)))

! 170:[multimeter] Multimeter 
      IVD1_1 = NRTCF
      NRTCF  = NRTCF + 5
      RVD1_1 = RTCF(IVD1_1) * P3PH3(SS(1), (IBRCH(1)+13), (IBRCH(1)+14),&
     & (IBRCH(1)+15),RTCF(IVD1_1+2),0)
      Pe = RVD1_1
      CALL DGTL_RMS3(256,SS(1),NT_5(1),NT_5(2),NT_5(3),RTCF(IVD1_1+3),1.&
     &0,0.0,RVD1_1)
      RVD1_1 = RTCF(IVD1_1+1)*RVD1_1
      Ve = RVD1_1

! 190:[ammeter] Current Meter 'Iibr'
      Iibr(1) = ( CBR((IBRCH(1)+4), SS(1)))
      Iibr(2) = ( CBR((IBRCH(1)+5), SS(1)))
      Iibr(3) = ( CBR((IBRCH(1)+6), SS(1)))

! 210:[multimeter] Multimeter 
      IVD1_1 = NRTCF
      NRTCF  = NRTCF + 5
      RVD1_1 = RTCF(IVD1_1) * P3PH3(SS(1), (IBRCH(1)+22), (IBRCH(1)+23),&
     & (IBRCH(1)+24),RTCF(IVD1_1+2),0)
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,1096460806,RVD1_1,"Pd")
      RVD1_1 = RTCF(IVD1_1) * Q3PH3(SS(1), (IBRCH(1)+22), (IBRCH(1)+23),&
     & (IBRCH(1)+24),RTCF(IVD1_1+2),0)
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,1096460806,RVD1_1,"Qd")
      Q0 = RVD1_1
      CALL DGTL_RMS3(256,SS(1),NT_2(1),NT_2(2),NT_2(3),RTCF(IVD1_1+3),1.&
     &0,0.0,RVD1_1)
      RVD1_1 = RTCF(IVD1_1+1)*RVD1_1
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,1096460806,RVD1_1,"Vd")
      IF (FIRSTSTEP) THEN
        CALL PSCAD_AGI2(ICALL_NO,1096460806,1,"hide1")
        CALL PSCAD_AGI2(ICALL_NO,1096460806,1,"hide2")
      ENDIF

! 220:[datatap] Scalar/Array Tap 
      Ib = Iibr(2)

! 230:[voltmetergnd] Voltmeter (Line - Ground) 'Vibr'
      Vibr(1) = EMTDC_VVDC(SS(1), NT_1(1), 0)
      Vibr(2) = EMTDC_VVDC(SS(1), NT_1(2), 0)
      Vibr(3) = EMTDC_VVDC(SS(1), NT_1(3), 0)

! 240:[multimeter] Multimeter 
      IVD1_1 = NRTCF
      NRTCF  = NRTCF + 5
      RVD1_1 = RTCF(IVD1_1) * P3PH3(SS(1), (IBRCH(1)+1), (IBRCH(1)+2), (&
     &IBRCH(1)+3),RTCF(IVD1_1+2),0)
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,512141270,RVD1_1,"Pd")
      P = RVD1_1
      RVD1_1 = RTCF(IVD1_1) * Q3PH3(SS(1), (IBRCH(1)+1), (IBRCH(1)+2), (&
     &IBRCH(1)+3),RTCF(IVD1_1+2),0)
      IF (UPDATE_AG) CALL PSCAD_AGRG2(ICALL_NO,512141270,RVD1_1,"Qd")
      Q = RVD1_1
